import json
import logging
import boto3
from botocore.exceptions import ClientError, ParamValidationError
import re
import os

logger = logging.getLogger()
logger.setLevel(logging.INFO)

sns_client = boto3.client('sns')

ALLOWED_TOPIC_ARN_PATTERN = re.compile(
    r'^arn:aws:sns:[a-z0-9-]+:\d{12}:[a-zA-Z0-9_-]+$'
)

MAX_MESSAGE_LENGTH = 256 * 1024  # 256 KB SNS limit
MAX_SUBJECT_LENGTH = 100

ALLOWED_NOTIFICATION_TYPES = frozenset([
    'alert',
    'info',
    'warning',
    'critical',
    'transactional',
    'promotional',
])

ALLOWED_ACCOUNT_ID = os.environ.get('ALLOWED_AWS_ACCOUNT_ID', '')
ALLOWED_TOPIC_PREFIX = os.environ.get('ALLOWED_TOPIC_PREFIX', '')


def validate_topic_arn(topic_arn):
    """Validate the SNS topic ARN format and allowed account."""
    if not isinstance(topic_arn, str):
        raise ValueError("Topic ARN must be a string.")

    if not ALLOWED_TOPIC_ARN_PATTERN.match(topic_arn):
        raise ValueError(f"Invalid topic ARN format: {topic_arn}")

    arn_parts = topic_arn.split(':')
    if len(arn_parts) != 6:
        raise ValueError("Malformed ARN.")

    account_id = arn_parts[4]
    topic_name = arn_parts[5]

    if ALLOWED_ACCOUNT_ID and account_id != ALLOWED_ACCOUNT_ID:
        raise ValueError("Topic ARN belongs to a disallowed AWS account.")

    if ALLOWED_TOPIC_PREFIX and not topic_name.startswith(ALLOWED_TOPIC_PREFIX):
        raise ValueError(f"Topic name must start with '{ALLOWED_TOPIC_PREFIX}'.")

    return topic_arn


def sanitize_string(value, max_length, field_name="field"):
    """Sanitize and validate a string input."""
    if not isinstance(value, str):
        raise ValueError(f"{field_name} must be a string.")

    value = value.strip()

    if not value:
        raise ValueError(f"{field_name} must not be empty.")

    if len(value) > max_length:
        raise ValueError(
            f"{field_name} exceeds maximum length of {max_length} characters."
        )

    return value


def validate_notification_type(notification_type):
    """Validate the notification type against allowed types."""
    if not isinstance(notification_type, str):
        raise ValueError("Notification type must be a string.")

    notification_type = notification_type.strip().lower()

    if notification_type not in ALLOWED_NOTIFICATION_TYPES:
        raise ValueError(
            f"Invalid notification type '{notification_type}'. "
            f"Allowed types: {', '.join(sorted(ALLOWED_NOTIFICATION_TYPES))}"
        )

    return notification_type


def validate_message_attributes(attributes):
    """Validate and sanitize message attributes."""
    if attributes is None:
        return {}

    if not isinstance(attributes, dict):
        raise ValueError("Message attributes must be a dictionary.")

    sanitized = {}
    allowed_data_types = {'String', 'Number', 'Binary'}

    for key, value in attributes.items():
        if not isinstance(key, str) or not key.strip():
            raise ValueError("Attribute keys must be non-empty strings.")

        if len(key) > 256:
            raise ValueError(f"Attribute key '{key[:50]}...' exceeds max length.")

        if not isinstance(value, dict):
            raise ValueError(f"Attribute value for '{key}' must be a dictionary.")

        data_type = value.get('DataType', '')
        if data_type not in allowed_data_types:
            raise ValueError(
                f"Invalid DataType '{data_type}' for attribute '{key}'."
            )

        sanitized_attr = {'DataType': data_type}

        if 'StringValue' in value:
            string_val = value['StringValue']
            if not isinstance(string_val, str):
                raise ValueError(
                    f"StringValue for attribute '{key}' must be a string."
                )
            if len(string_val) > 256 * 1024:
                raise ValueError(
                    f"StringValue for attribute '{key}' exceeds max length."
                )
            sanitized_attr['StringValue'] = string_val
        elif 'BinaryValue' in value:
            sanitized_attr['BinaryValue'] = value['BinaryValue']
        else:
            raise ValueError(
                f"Attribute '{key}' must have StringValue or BinaryValue."
            )

        sanitized[key] = sanitized_attr

    if len(sanitized) > 10:
        raise ValueError("Maximum of 10 message attributes allowed.")

    return sanitized


def build_message_body(message, notification_type, metadata=None):
    """Build a structured message body."""
    body = {
        'notification_type': notification_type,
        'message': message,
    }

    if metadata and isinstance(metadata, dict):
        safe_metadata = {}
        for k, v in metadata.items():
            if isinstance(k, str) and isinstance(v, (str, int, float, bool)):
                safe_metadata[sanitize_string(k, 128, "metadata key")] = v
        body['metadata'] = safe_metadata

    return json.dumps(body, default=str)


def publish_message(topic_arn, message, subject=None, message_attributes=None):
    """Publish a message to the specified SNS topic."""
    publish_params = {
        'TopicArn': topic_arn,
        'Message': message,
    }

    if subject:
        publish_params['Subject'] = subject

    if message_attributes:
        publish_params['MessageAttributes'] = message_attributes

    try:
        response = sns_client.publish(**publish_params)
        message_id = response.get('MessageId', 'unknown')
        logger.info(
            "Message published successfully. MessageId: %s, TopicArn: %s",
            message_id,
            topic_arn
        )
        return {
            'success': True,
            'message_id': message_id,
        }
    except ClientError as e:
        error_code = e.response['Error']['Code']
        error_message = e.response['Error']['Message']
        logger.error(
            "Failed to publish message. Error: %s - %s, TopicArn: %s",
            error_code,
            error_message,
            topic_arn
        )
        raise
    except ParamValidationError as e:
        logger.error("Parameter validation error: %s", str(e))
        raise ValueError(f"Invalid parameters: {str(e)}")


def publish_batch(topic_arn, messages):
    """Publish multiple messages in batch to an SNS topic."""
    if not isinstance(messages, list) or len(messages) == 0:
        raise ValueError("Messages must be a non-empty list.")

    if len(messages) > 10:
        raise ValueError("Batch publish supports a maximum of 10 messages.")

    entries = []
    for idx, msg in enumerate(messages):
        if not isinstance(msg, dict):
            raise ValueError(f"Message at index {idx} must be a dictionary.")

        notification_type = validate_notification_type(
            msg.get('notification_type', 'info')
        )
        message_content = sanitize_string(
            msg.get('message', ''), MAX_MESSAGE_LENGTH, "message"
        )
        subject = msg.get('subject')
        metadata = msg.get('metadata')

        body = build_message_body(message_content, notification_type, metadata)

        entry = {
            'Id': str(idx),
            'Message': body,
        }

        if subject:
            entry['Subject'] = sanitize_string(
                subject, MAX_SUBJECT_LENGTH, "subject"
            )

        msg_attrs = msg.get('message_attributes')
        if msg_attrs:
            entry['MessageAttributes'] = validate_message_attributes(msg_attrs)

        entries.append(entry)

    try:
        response = sns_client.publish_batch(
            TopicArn=topic_arn,
            PublishBatchRequestEntries=entries
        )

        successful = response.get('Successful', [])
        failed = response.get('Failed', [])

        if failed:
            logger.warning(
                "Some messages failed in batch publish. Failed: %s",
                json.dumps(failed, default=str)
            )

        logger.info(
            "Batch publish completed. Successful: %d, Failed: %d, TopicArn: %s",
            len(successful),
            len(failed),
            topic_arn
        )

        return {
            'success': len(failed) == 0,
            'successful': [s.get('MessageId') for s in successful],
            'failed': failed,
        }
    except ClientError as e:
        error_code = e.response['Error']['Code']
        error_message = e.response['Error']['Message']
        logger.error(
            "Batch publish failed. Error: %s - %s, TopicArn: %s",
            error_code,
            error_message,
            topic_arn
        )
        raise


def lambda_handler(event, context):
    """
    Lambda handler for publishing messages to SNS topics.

    Expected event structure for single message:
    {
        "action": "publish",
        "topic_arn": "arn:aws:sns:us-east-1:123456789012:MyTopic",
        "notification_type": "alert",
        "message": "Something happened",
        "subject": "Alert Notification",  # optional
        "metadata": {"key": "value"},  # optional
        "message_attributes": {  # optional
            "attr_name": {
                "DataType": "String",
                "StringValue": "attr_value"
            }
        }
    }

    Expected event structure for batch:
    {
        "action": "publish_batch",
        "topic_arn": "arn:aws:sns:us-east-1:123456789012:MyTopic",
        "messages": [
            {
                "notification_type": "info",
                "message": "First message",
                "subject": "Info 1"
            },
            {
                "notification_type": "warning",
                "message": "Second message"
            }
        ]
    }
    """
    try:
        if not isinstance(event, dict):
            return {
                'statusCode': 400,
                'body': json.dumps({'error': 'Invalid event format.'})
            }

        action = event.get('action', 'publish')
        if action not in ('publish', 'publish_batch'):
            return {
                'statusCode': 400,
                'body': json.dumps({'error': f"Invalid action: {action}"})
            }

        # Validate topic ARN
        raw_topic_arn = event.get('topic_arn', '')
        topic_arn = validate_topic_arn(raw_topic_arn)

        if action == 'publish_batch':
            messages = event.get('messages', [])
            result = publish_batch(topic_arn, messages)
            return {
                'statusCode': 200,
                'body': json.dumps(result, default=str)
            }

        # Single message publish
        notification_type = validate_notification_type(
            event.get('notification_type', 'info')
        )

        message_content = sanitize_string(
            event.get('message', ''), MAX_MESSAGE_LENGTH, "message"
        )

        subject = event.get('subject')
        if subject:
            subject = sanitize_string(subject, MAX_SUBJECT_LENGTH, "subject")

        metadata = event.get('metadata')
        message_attributes = validate_message_attributes(
            event.get('message_attributes')
        )

        # Add notification type as a message attribute for filtering
        message_attributes['notification_type'] = {
            'DataType': 'String',
            'StringValue': notification_type,
        }

        structured_message = build_message_body(
            message_content, notification_type, metadata
        )

        result = publish_message(
            topic_arn=topic_arn,
            message=structured_message,
            subject=subject,
            message_attributes=message_attributes,
        )

        return {
            'statusCode': 200,
            'body': json.dumps(result, default=str)
        }

    except ValueError as e:
        logger.warning("Validation error: %s", str(e))
        return {
            'statusCode': 400,
            'body': json.dumps({'error': str(e)})
        }
    except ClientError as e:
        error_code = e.response['Error']['Code']
        if error_code == 'NotFound':
            return {
                'statusCode': 404,
                'body': json.dumps({'error': 'SNS topic not found.'})
            }
        elif error_code == 'AuthorizationError':
            return {
                'statusCode': 403,
                'body': json.dumps({'error': 'Not authorized to publish to this topic.'})
            }
        else:
            return {
                'statusCode': 500,
                'body': json.dumps({'error': 'Failed to publish message to SNS.'})
            }
    except Exception:
        logger.exception("Unexpected error in lambda_handler")
        return {
            'statusCode': 500,
            'body': json.dumps({'error': 'Internal server error.'})
        }